using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record ClassifyRequest(string Subject, string Description, int Priority);

public record ClassifyResponse(string PredictedCategory, Dictionary<string, float> Confidence);

public record EvaluationMetrics
{
    public double MicroAccuracy { get; init; }
    public double MacroAccuracy { get; init; }
    public double LogLoss { get; init; }
    public double LogLossReduction { get; init; }
    public int CrossValidationFolds { get; init; }
    public int DatasetSize { get; init; }
    public string ConfusionMatrix { get; init; } = string.Empty;
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    public EvaluationMetrics? Metrics { get; private set; }
    public string[] ClassLabels { get; private set; } = [];

    public void TrainAndEvaluate(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized",
                nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate for evaluation metrics (better than train/test split for small datasets)
        var cvResults = mlContext.MulticlassClassification.CrossValidate(
            data, pipeline, numberOfFolds: 3);

        var bestFold = cvResults.OrderByDescending(r => r.Metrics.MicroAccuracy).First();

        Metrics = new EvaluationMetrics
        {
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
            CrossValidationFolds = cvResults.Length,
            DatasetSize = data.GetColumn<string>(nameof(TicketData.Category)).Count(),
            ConfusionMatrix = bestFold.Metrics.ConfusionMatrix.GetFormattedConfusionTable()
        };

        // Train on full dataset for the production model
        var model = pipeline.Fit(data);

        // Extract class labels from the Score column's slot names
        var outputSchema = model.GetOutputSchema(data.Schema);
        var scoreColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        ClassLabels = slotNames.DenseValues().Select(x => x.ToString()).ToArray();

        mlContext.Model.Save(model, data.Schema, modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly TicketModelService _modelService;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        TicketModelService modelService)
    {
        _predictionPool = predictionPool;
        _modelService = modelService;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _modelService.ClassLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_modelService.ClassLabels[i]] = prediction.Score[i];
        }

        return Ok(new ClassifyResponse(prediction.PredictedCategory, confidence));
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        if (_modelService.Metrics is null)
            return StatusCode(503, "Model not yet trained");

        return Ok(_modelService.Metrics);
    }
}

