using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

// Train the model at startup and capture evaluation metrics
var modelService = new TicketModelService();
modelService.TrainAndEvaluate(dataPath, modelPath);

builder.Services.AddSingleton(modelService);
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapPost("/api/tickets/classify", (
    ClassifyRequest request,
    PredictionEnginePool<TicketData, TicketPrediction> pool,
    TicketModelService svc) =>
{
    var input = new TicketData
    {
        Subject = request.Subject,
        Description = request.Description,
        Priority = request.Priority
    };

    var prediction = pool.Predict(input);

    var confidence = new Dictionary<string, float>();
    for (int i = 0; i < svc.ClassLabels.Length && i < prediction.Score.Length; i++)
        confidence[svc.ClassLabels[i]] = prediction.Score[i];

    return Results.Ok(new ClassifyResponse(prediction.PredictedCategory, confidence));
});

app.MapGet("/api/tickets/metrics", (TicketModelService svc) =>
{
    return svc.Metrics is null
        ? Results.StatusCode(503)
        : Results.Ok(svc.Metrics);
});

app.Run();

